import{_ as e,o as t,c as a,Q as l}from"./chunks/framework.3daba8ea.js";const P=JSON.parse('{"title":"hostPath [不推荐]","description":"","frontmatter":{},"headers":[],"relativePath":"doc/DevOps/Kubernetes/基础/Volume/type/hostPath.md","filePath":"packages/doc/src/DevOps/Kubernetes/基础/Volume/type/hostPath.md","lastUpdated":1704383113000}'),o={name:"doc/DevOps/Kubernetes/基础/Volume/type/hostPath.md"},i=l('<h1 id="hostpath-不推荐" tabindex="-1">hostPath [不推荐] <a class="header-anchor" href="#hostpath-不推荐" aria-label="Permalink to &quot;hostPath [不推荐]&quot;">​</a></h1><p>挂载Node文件系统（Pod所在节点）上文件或者目 录到Pod中的容器。</p><ul><li>不推荐使用, 有安全隐患</li><li>如果一定要用的话，请设置只读权限</li></ul><h2 id="场景" tabindex="-1">场景 <a class="header-anchor" href="#场景" aria-label="Permalink to &quot;场景&quot;">​</a></h2><ul><li>需要访问宿主机文件</li></ul><h2 id="缺点" tabindex="-1">缺点 <a class="header-anchor" href="#缺点" aria-label="Permalink to &quot;缺点&quot;">​</a></h2><ul><li>安全性问题</li><li>无法跨节点共享</li><li>无法跨Pod共享</li><li>宿主机的数据不会随着pod的调度而更改位置</li></ul><h2 id="配置" tabindex="-1">配置 <a class="header-anchor" href="#配置" aria-label="Permalink to &quot;配置&quot;">​</a></h2><ul><li><p>type: Directory 给定路径中必须存在目录，不会自动创建</p></li><li><p>type: File 给定路径中必须存在文件，不会自动创建</p></li><li><p>type: DirectoryOrCreate 如果给定路径上不存在任何内容，则将根据需要在那里创建一个空目录，权限设置为0755，与Kubelet具有相同的组和所有权。</p></li><li><p>type: FileOrCreate 如果给定路径上不存在任何内容，则将根据需要在那里创建一个空文件，权限设置为0644，与Kubelet具有相同的组和所有权。</p></li></ul>',9),r=[i];function s(h,p,d,c,n,u){return t(),a("div",null,r)}const m=e(o,[["render",s]]);export{P as __pageData,m as default};
